    const aStr = sections[1] ? sections[1].trim() : '';
    return `\n\n
<div class="mdp-mod-faq" style="--faq-color: ${color};">
<div class="mdp-faq-item mdp-faq-q">
<div class="mdp-faq-icon">Q</div>
<div class="mdp-faq-text">

${qStr}

</div>
</div>
<div class="mdp-faq-item mdp-faq-a">
<div class="mdp-faq-icon">A</div>
<div class="mdp-faq-text">

${aStr}

</div>
</div>
</div>
\n\n`;
